const pais = $json["Pais"] || "Colombia";
const entorno = $json["Entorno"] || "Producción";

const resultados = $items("Ejecutar en SQL Server (SELECT)", 0, 0);

let inserts = resultados.map(item => {
  const row = item.json;
  const anio = row.ano;
  const mes = row.mes;
  const cantidad = row.Emitidos || row.cantidad;

  return {
    insertSQL: `INSERT INTO ValoresCOMFIAR (Pais, Entorno, Anio, Mes, Cantidad)
                VALUES ('${pais}', '${entorno}', ${anio}, ${mes}, ${cantidad});`,
    registro: { pais, entorno, anio, mes, cantidad }
  };
});

// Tomamos el último registro
const ultimo = inserts[inserts.length - 1];

return [{
  json: {
    insertSQL: inserts.map(i => i.insertSQL).join("\n"),
    ultimoRegistro: ultimo.registro
  }
}];

